+        };
+        let latency_query_reserve_pct = if self.latency_query_reserve_pct > 100 {
+            100
+        } else {
+            self.latency_query_reserve_pct
+        };
+        let starvation_guard_cycles = if self.starvation_guard_cycles == 0 {
