+        let io_base = config.io_ceiling_bytes_per_sec as f64;
+        let load_base = f64::from(config.load_ceiling_per_mille) / 1000.0;
+        let (memory_degraded_pct, constrained_pad, emergency_pad): (f64, f64, f64) =
