+                crate::config::PressureProfile::Strict => (75.0, 15.0, 8.0),
+                crate::config::PressureProfile::Performance => (85.0, 10.0, 10.0),
+                crate::config::PressureProfile::Degraded => (90.0, 8.0, 7.0),
